[170] يُنظر: ((تفسير ابن جرير)) (21/256)، ((الوسيط)) للواحدي (4/137)، ((الإيمان)) لابن تيمية (ص: 196)، ((تفسير ابن كثير)) (7/337)، ((تفسير القاسمي)) (8/493). قال الرازي في قولِه تعالى: يَقُولُونَ بِأَلْسِنَتِهِمْ مَا لَيْسَ فِي قُلُوبِهِمْ: (هذا يحتَمِلُ أمْرَينِ؛ أحَدُهما: أن يكونَ التَّكذيبُ راجِعًا إلى قَولِهم: فَاسْتَغْفِرْ لَنَا، وتحقيقُه هو أنَّهم أظهَروا أنَّهم يَعتَقِدونَ أنَّهم مُسِيئونَ بالتَّخَلُّفِ حتَّى استَغفَروا، ولم يكُنْ في اعتِقادِهم ذلك، بل كانوا يَعتَقِدونَ أنَّهم بالتَّخَلُّفِ مُحسِنونَ. ثانيهما: قالوا: شَغَلَتْنَا؛ إشارةً إلى أنَّ امتِناعَنا لهذا لا غَيرُ، ولم يكُنْ ذلك في اعتِقادِهم، بل كانوا يَعتَقِدونَ امتِناعَهم لاعتقادِ أنَّ النَّبيَّ صلَّى اللهُ عليه وسلَّم والمؤمِنينَ يُقهَرونَ ويُغلَبونَ، كما قال بَعْدَه: بَلْ ظَنَنْتُمْ أَنْ لَنْ يَنْقَلِبَ الرَّسُولُ وَالْمُؤْمِنُونَ إِلَى أَهْلِيهِمْ أَبَدًا
[الفتح: 12]
). ((تفسير الرازي)) (28/74). وممَّن قال بأنَّ المرادَ أنَّهم في طلَبِ الاستِغفارِ عن التَّخَلُّفِ كاذِبون؛ لأنَّهم لا يُبالون أَسْتَغفَرَ لهم النَّبيُّ صلَّى الله عليه وسلَّم أمْ لا: ابنُ جرير، والسمرقندي، ومكِّي، والواحدي، وابن الجوزي، والخازن، وابن كثير، والسعدي. يُنظر: ((تفسير ابن جرير)) (21/256)، ((تفسير السمرقندي)) (3/314)، ((الهداية إلى بلوغ النهاية)) لمكي (11/6946)، ((الوسيط)) للواحدي (4/137)، ((تفسير ابن الجوزي)) (4/131)، ((تفسير الخازن)) (4/157)، ((تفسير ابن كثير)) (7/337)، ((تفسير السعدي)) (ص: 792). وممَّن قال: إنَّ المرادَ تكذيبُهم في الاعتِذارِ والاستِغفارِ: الثعلبيُّ، والزمخشري، والبيضاوي، وأبو حيَّان، والبِقاعي، وأبو السعود، والألوسي، والقاسمي. يُنظر: ((تفسير الثعلبي)) (9/45)، ((تفسير الزمخشري)) (4/336)، ((تفسير البيضاوي)) (5/128)، ((تفسير أبي حيان)) (9/488)، ((نظم الدرر)) للبقاعي (18/301)، ((تفسير أبي السعود)) (8/107)، ((تفسير الألوسي)) (13/253)، ((تفسير القاسمي)) (8/493). قال القاسمي: (قوله تعالى: يَقُولُونَ بِأَلْسِنَتِهِمْ مَا لَيْسَ فِي قُلُوبِهِمْ تكذيبٌ لهم في اعتِذارِهم، وأنَّ الَّذي خلَّفَهم ليس بما يَقولون، وإنَّما هو الشَّكُّ في الله، والنِّفاقُ. وكذا طلَبُهم للاستِغفارِ أيضًا ليس بصادرٍ عن حقيقةٍ؛ لأنَّه بغيرِ تَوبةٍ منهم، ولا ندَمٍ على ما سلَف منهم مِن معصيةِ التَّخلُّفِ). ((تفسير القاسمي)) (8/493). وقال أبو حيَّان: (ولَمَّا عَلِموا أنَّ ذلك التَّخلُّفَ عن الرَّسولِ كان معصيةً، سألوا أن يَستغفِرَ لهم. يَقُولُونَ بِأَلْسِنَتِهِمْ مَا لَيْسَ فِي قُلُوبِهِمْ: الظَّاهرُ أنَّه راجِعٌ إلى الجُملتَينِ المَقولتَينِ مِن الشُّغلِ وطلَبِ الاستِغفارِ، لأنَّ قولَهم: شَغَلَتْنَا كَذِبٌ، وطلَبَ الاستِغفارِ خُبثٌ منهم، وإظهارُ أنَّهم مؤمِنون عاصون). ((تفسير أبي حيان)) (9/488).

[292] يُنظر: ((تفسير ابن جرير)) (21/283)، ((تفسير القرطبي)) (16/279)، ((زاد المعاد)) لابن القيم (3/278)، ((تفسير ابن كثير)) (7/341)، ((تفسير السعدي)) (ص: 794). قال الشوكاني: (وَلِتَكُونَ آَيَةً لِلْمُؤْمِنِينَ اللَّامُ يجوزُ أن تتعَلَّق بفِعلٍ مَحذوفٍ يُقَدَّرُ بَعْدَه، أي: فَعَل ما فَعَل مِنَ التَّعجيلِ والكَفِّ؛ لِتَكونَ آيةً، أو على عِلَّةٍ مَحذوفةٍ تَقديرُها: وَعَد فعَجَّلَ وكَفَّ؛ لِتَنتَفِعوا بذلك، ولِتَكونَ آيةً. وقيل: إنَّ الواوَ مَزيدةٌ، واللَّامَ لِتَعليلِ ما قَبْلَه، أي: وكَفَّ لِتَكونَ، والمعنى: ذلك الكَفُّ آيةٌ يُعلَمُ بها صِدقُ رَسولِ اللهِ صلَّى اللهُ عليه وسلَّم في جميعِ ما يَعِدُكم به). ((تفسير الشوكاني)) (5/61)، ويُنظر: ((تفسير الزمخشري)) (4/341). قيل: المرادُ: ولِيَكونَ كَفُّهم عن المؤمِنينَ آيةً لهم. وممَّن ذهب إلى هذا المعنى: ابنُ جرير، والنسفي، وابن جُزَي. يُنظر: ((تفسير ابن جرير)) (21/283)، ((تفسير النسفي)) (3/340)، ((تفسير ابن جزي)) (2/289). ويُنظر أيضًا: ((زاد المعاد)) لابن القيم (3/278). وممَّن قال بنحوِ هذا القولِ مِن السَّلفِ: قَتادةُ. يُنظر: ((تفسير ابن جرير)) (21/283). قال ابنُ كثير: (أي: يَعتَبِرونَ بذلك؛ فإنَّ اللهَ حافِظُهم وناصِرُهم على سائِرِ الأعداءِ مع قِلَّةِ عَدَدِهم، ولِيَعلَموا بصَنيعِ اللهِ هذا بهم أنَّه العَليمُ بعواقِبِ الأُمورِ، وأنَّ الخِيَرةَ فيما يَختارُه لِعِبادِه المُؤمِنينَ وإنْ كَرِهوه في الظَّاهِرِ، كما قال تعالى: وَعَسَى أَنْ تَكْرَهُوا شَيْئًا وَهُوَ خَيْرٌ لَكُمْ
[البقرة: 216]
). ((تفسير ابن كثير)) (7/341). وقيل: المعنى: ولِتَكونَ الغَنيمةُ آيةً للمُؤمِنينَ. وممَّن ذهب إلى هذا المعنى: مكِّي، والواحدي، والخازن، والسعدي. يُنظر: ((الهداية إلى بلوغ النهاية)) لمكي (11/6959)، ((الوسيط)) للواحدي (4/140)، ((تفسير الخازن)) (4/161)، ((تفسير السعدي)) (ص: 794). قال السعدي: (وَلِتَكُونَ هذه الغَنيمةُ آَيَةً لِلْمُؤْمِنِينَ يَستَدِلُّونَ بها على خَبَرِ اللهِ الصَّادِقِ، ووعَدِه الحَقِّ، وثوابِه للمُؤمِنينَ، وأنَّ الَّذي قَدَّرَها سيُقَدِّرُ غَيرَها). ((تفسير السعدي)) (ص: 794). وقيل المعنى: ولِتَكونَ هزيمتُهم وسلامتُكم آيةً للمؤمنينَ. وممَّن اختاره: الثعلبي، والبغوي، والقرطبي. يُنظر: ((تفسير الثعلبي)) (9/48)، ((تفسير البغوي)) (4/229)، ((تفسير القرطبي)) (16/279).
